#!/usr/bin/env bash
# Verify the integrity of the vendored budoux.esm.js.
#
# Default: compare the local file's SHA-256 against METADATA.json.
# --remote: also re-fetch the bundle from jsDelivr and compare byte-for-byte.
#
# Note: the /+esm bundle is dynamically generated by jsDelivr (Rollup + Terser),
# so jsDelivr does NOT publish an authoritative hash for it. The only upstream
# hashes jsDelivr exposes are for static npm package files via
# https://data.jsdelivr.com/v1/packages/npm/budoux@<ver>?structure=flat
# Those are SHA-256 (base64) over the original npm tarball contents. Since we
# vendored the convenience bundle instead of individual package files,
# --remote verification asks "content matches what jsDelivr is serving right
# now", not a signed-upstream check.

set -euo pipefail

VENDOR_DIR="$(cd "$(dirname "$0")" && pwd)"
JS_FILE="$VENDOR_DIR/budoux.esm.js"
METADATA_FILE="$VENDOR_DIR/METADATA.json"

hash_sha256_base64() {
  openssl dgst -sha256 -binary "$1" | base64
}

read_metadata_field() {
  python3 -c "import json; print(json.load(open('$METADATA_FILE'))['$1'])"
}

# ----- Step 1: local file vs METADATA.json -----

local_hash="$(hash_sha256_base64 "$JS_FILE")"
recorded_hash="$(read_metadata_field integrity | sed 's/^sha256-//')"

echo "File:     $JS_FILE"
echo "Local:    sha256-$local_hash"
echo "METADATA: sha256-$recorded_hash"

if [ "$local_hash" = "$recorded_hash" ]; then
  echo "[OK] Local file matches METADATA.json"
else
  echo "[FAIL] Vendored file has drifted from METADATA.json"
  exit 1
fi

# ----- Step 2 (optional): re-fetch from jsDelivr and compare -----

if [ "${1:-}" = "--remote" ]; then
  source_url="$(read_metadata_field source)"
  tmp="$(mktemp)"
  trap 'rm -f "$tmp"' EXIT

  echo ""
  echo "Fetching $source_url"
  curl -sS --fail "$source_url" -o "$tmp"

  remote_hash="$(hash_sha256_base64 "$tmp")"
  echo "Remote:   sha256-$remote_hash"

  if [ "$local_hash" = "$remote_hash" ]; then
    echo "[OK] Remote bundle is byte-identical to the vendored copy"
  else
    echo "[WARN] Remote bundle differs (jsDelivr may have re-bundled)"
    exit 2
  fi
fi
